-- ============================================================================
-- legal_docs — admin-editable Terms / Privacy content.
--
-- Each row holds one document's i18n dictionary as { "en": {...}, "ja": {...} }.
-- terms.html reads it (anon, public) and overlays it on the baked-in defaults,
-- so the page still works if the row is missing. The superadmin Terms editor
-- writes it through the /api/sb service_role proxy (bypasses RLS).
--
-- Seeded here with the CURRENT terms.html text so the editor opens populated.
-- Idempotent: re-running refreshes the seed only if you uncomment the DO UPDATE.
-- ============================================================================
create table if not exists public.legal_docs (
  slug        text primary key,
  dict        jsonb not null default '{}'::jsonb,
  updated_at  timestamptz not null default now(),
  updated_by  text
);

alter table public.legal_docs enable row level security;

-- Public read: Terms/Privacy are public pages (anon SELECT).
drop policy if exists legal_docs_public_read on public.legal_docs;
create policy legal_docs_public_read on public.legal_docs
  for select using (true);
-- No write policy on purpose — the superadmin console writes via the
-- service_role proxy, which bypasses RLS. anon/authenticated cannot write.

-- Seed 'terms' from the current baked-in dictionary (insert once; on conflict
-- leave existing admin edits intact).
insert into public.legal_docs (slug, dict, updated_by)
values ('terms', '{"en":{"back":"Back","banner":"<strong>Draft template.</strong> This document is a working version for Journey Junction''s planner platform. Before going live, please have it reviewed by qualified legal counsel for compliance with Japanese consumer and contractor law.","eyebrow":"Planner Agreement","title":"Terms of <em>Service</em>","lastUpdated":"Last updated: 16 May 2026 · Governed by the laws of Japan","s1.title":"Who we are","s1.p1":"<strong>Journey Junction</strong> (\"we\", \"us\", \"Journey Junction\") is a travel-planning marketplace serving the Japan market. We connect independent itinerary planners (\"Planners\", \"you\") with travelers visiting Japan. These Terms govern your use of Journey Junction''s planner-facing services, dashboard, and any related tools.","s1.p2":"By creating a planner account, you confirm you have read, understood, and agreed to be bound by these Terms and our <a href=\"privacy.html\">Privacy Policy</a>.","s2.title":"Eligibility","s2.p1":"To register as a Planner you must:","s2.l1":"be at least <strong>18 years old</strong>;","s2.l2":"have the legal right to work as an independent contractor in your country of residence;","s2.l3":"hold a valid bank account in your own name able to receive JPY (¥) transfers;","s2.l4":"provide accurate, up-to-date information during signup and keep your profile current.","s3.title":"Your role as a Planner","s3.p1":"Planners work with Journey Junction as <strong>independent contractors</strong>, not employees. You choose which sets to accept from your dashboard and are responsible for delivering itineraries that meet our published quality standards.","s3.h1":"Obligations","s3.l1":"<strong>Quality.</strong> Each itinerary must be original, factually accurate, and tailored to the traveler''s brief.","s3.l2":"<strong>Deadlines.</strong> Complete sets by the deadline shown on your dashboard. If you can''t, request an extension before it lapses.","s3.l3":"<strong>Professionalism.</strong> Communicate respectfully with travelers and support staff. Discriminatory, harassing, or misleading content is not permitted.","s3.l4":"<strong>Originality.</strong> You warrant that itineraries, images, and notes you upload are your own work or properly licensed for use.","s4.title":"Commission and payouts","s4.p1":"Each set''s commission is displayed on your dashboard before you claim it. Payouts are made in <strong>Japanese yen (¥)</strong> via bank transfer, depending on the payout method you set in your profile.","s4.h1":"Payout timing","s4.p2":"Commission is released after all 15 plans in a set are reviewed and approved by admin. Standard release time is within <strong>24 hours of final approval</strong>, subject to banking-day delays.","s4.hW":"Performance bonus","s4.pW":"Planners who complete and receive approval for at least <strong>2 sets in a 7-day cycle</strong> are awarded a <strong>¥150,000 performance bonus</strong>, credited to their wallet after the cycle ends. The first cycle begins on the date the planner completes their first-ever set; subsequent cycles run as consecutive 7-day windows anchored to that same date. The bonus is in addition to per-plan commission, and is not a guaranteed salary. Cycles in which fewer than 2 sets are completed and approved do not qualify.","s4.h2":"Wallet protection buffer","s4.p3":"Journey Junction may hold a <strong>protection buffer</strong> in your wallet to cover post-approval adjustments (disputed plans, reversals) without clawing back from your bank. The buffer amount, if any, is set by the platform and shown in your Wallet at any time. Anything earned above the buffer is fully withdrawable. We may revise the buffer amount from time to time at our discretion.","s6.title":"Intellectual property","s6.p1":"You retain authorship of your itinerary content. By submitting it to Journey Junction, you grant us a worldwide, non-exclusive, royalty-free license to store, display, and deliver the itinerary to the traveler it was prepared for. We will not republish your work outside the platform without your separate consent.","s7.title":"Prohibited conduct","s7.p1":"You agree not to:","s7.l1":"solicit travelers off the platform, or share contact details to circumvent Journey Junction;","s7.l2":"upload plagiarised content, stock AI output passed off as original, or content that infringes third-party rights;","s7.l3":"misrepresent your identity, qualifications, or residency;","s7.l4":"use the platform to promote illegal activity or unlicensed services;","s7.l5":"reverse-engineer, scrape, or abuse the Journey Junction APIs or dashboard.","s8.title":"Suspension and termination","s8.p1":"We may suspend or terminate your planner account, with or without prior notice, for repeated missed deadlines, low-quality output, abuse of the support channel, prohibited conduct, or on regulatory grounds.","s8.p2":"If terminated, you forfeit access to unclaimed sets and any unreleased commission pending adjudication of outstanding issues. Commissions already approved and released remain yours.","s9.title":"Liability and disclaimers","s9.p1":"Journey Junction is provided <strong>\"as is\"</strong>. We make no guarantees about the volume of sets available, earnings you may achieve, or uninterrupted service. To the maximum extent permitted by law, our aggregate liability to you for any dispute is limited to the commission paid to you in the <strong>three months preceding the claim</strong>.","s10.title":"Changes to these Terms","s10.p1":"We may update these Terms from time to time. Material changes will be announced via the dashboard at least 14 days before they take effect. Continued use of the platform after that date constitutes acceptance.","s11.title":"Governing law","s11.p1":"These Terms are governed by the laws of <strong>Japan</strong>. Although Journey Junction Ltd is incorporated in the United Kingdom, the service is provided to the Japan market and any dispute not resolved informally will be submitted to the exclusive jurisdiction of the Tokyo District Court (東京地方裁判所).","contact.title":"Contact","contact.body":"Questions about these Terms? Reach out via the <a href=\"support.html\">in-app support chat</a>, or email <strong>hello@thejourneyjunction.co.uk</strong>.","company.title":"Company information","company.body":"<strong>Journey Junction Ltd</strong><br>Company number 15791277 · Incorporated 20 June 2024<br>Registered office: Flat 2, 64 Heathmere Drive, Birmingham, West Midlands, B37 5EU, United Kingdom<br>Director: Midhun Peter"},"ja":{"back":"戻る","banner":"<strong>ドラフトのテンプレートです。</strong> 本書類は Journey Junction のプランナー向けプラットフォーム用の作業中バージョンです。公開前に、日本の消費者保護法および業務委託契約に関する法令への適合性について、有資格の法律顧問による確認を受けてください。","eyebrow":"プランナー契約","title":"<em>利用</em>規約","lastUpdated":"最終更新日：2026年5月16日 · 日本法に準拠","s1.title":"当社について","s1.p1":"<strong>Journey Junction</strong>（以下「当社」）は、日本を訪れる旅行者向けに旅程作成サービスを提供するプラットフォームです。当社は、独立した訪日旅行プランナー（以下「プランナー」）と、日本を訪れる旅行者をつなぎます。本規約は、Journey Junction がプランナー向けに提供するサービス、ダッシュボード、および関連するすべてのツールのご利用に適用されます。","s1.p2":"プランナーアカウントを作成した時点で、本規約および当社の<a href=\"privacy.html\">プライバシーポリシー</a>を読み、理解し、これらに拘束されることに同意したものとみなされます。","s2.title":"利用資格","s2.p1":"プランナーとして登録するには、以下の要件を満たす必要があります：","s2.l1":"<strong>18歳以上</strong>であること。","s2.l2":"お住まいの国において、独立した業務委託者として就労する法的権利を有していること。","s2.l3":"報酬を受け取るための有効なお支払い方法を登録できること。","s2.l4":"登録の際に正確かつ最新の情報を提供し、プロフィールを常に最新の状態に保つこと。","s3.title":"プランナーとしての役割","s3.p1":"プランナーは、従業員としてではなく<strong>独立した業務委託者</strong>として Journey Junction と協働します。プランナーは、ダッシュボード上で対応可能なセットを確認し、当社が定める品質基準に沿った旅程を作成する責任を負います。","s3.h1":"義務","s3.l1":"<strong>品質：</strong>各旅程は、事実に基づき、旅行者の依頼内容に合わせて正確かつ実用的に作成する必要があります。","s3.l2":"<strong>期限：</strong>ダッシュボードに表示された期限までにセットを完成させてください。間に合わない場合は、期限が経過する前に延長を申請してください。","s3.l3":"<strong>プロフェッショナリズム：</strong>旅行者およびサポートスタッフと敬意をもってコミュニケーションを行ってください。差別的、嫌がらせ的、または誤解を招く内容は許可されません。","s3.l4":"<strong>独自性：</strong>アップロードする旅程、画像、メモが、ご自身の制作物であるか、当該用途について適切にライセンスされたものであることを保証するものとします。","s4.title":"報酬および支払い","s4.p1":"各セットまたはプランごとの報酬額は、対応前にダッシュボードに表示されます。報酬は、プロフィールで設定したお支払い方法に応じて、<strong>日本円（¥）</strong>にて支払われます。","s4.h1":"支払いのタイミング","s4.p2":"報酬は、対象となるセットまたはプランが管理者により確認・承認された後に支払われます。標準的な支払い時期は<strong>最終承認から24時間以内</strong>ですが、銀行営業日の都合により遅れる場合があります。","s4.hW":"条件達成ボーナス","s4.pW":"<strong>連続する7日間のサイクル内に少なくとも2つのセット</strong>を完了し、承認されたプランナーには、サイクル終了後に<strong>条件達成ボーナス¥150,000</strong>がウォレットに付与されます。最初のサイクルは、プランナーが初めてセットを完了した日に開始され、以降のサイクルは同じ日付を起点とする連続する7日間の期間として進行します。このボーナスは、プランごとの報酬に加えて支払われるものであり、固定給を保証するものではありません。完了・承認されたセットが2つ未満のサイクルは対象外となります。","s4.h2":"ウォレット保護バッファ","s4.p3":"Journey Junction は、承認後の調整（争議のあるプランや取消など）に対応するため、プランナーの銀行口座から資金を回収することなく、ウォレット内に<strong>保護バッファ</strong>を留保する場合があります。バッファの金額は（設定される場合）プラットフォームが定め、いつでもウォレットに表示されます。バッファを超えて獲得した金額はすべて出金可能です。当社は、当社の裁量により、随時バッファの金額を改定することがあります。","s6.title":"知的財産","s6.p1":"プランナーは、ご自身の旅程コンテンツの著作者としての地位を保持します。これを Journey Junction に提出することにより、プランナーは当社に対し、当該旅程をその作成対象である旅行者に保存・表示・提供するための、全世界的・非独占的・ロイヤリティフリーのライセンスを付与します。当社は、プランナーの別途の同意なしに、プランナーの制作物をプラットフォーム外で再公開することはありません。","s7.title":"禁止行為","s7.p1":"プランナーは、以下の行為を行わないことに同意するものとします：","s7.l1":"プラットフォーム外で旅行者を勧誘すること、または Journey Junction を迂回するために連絡先を共有すること。","s7.l2":"盗用したコンテンツ、第三者の権利を侵害するコンテンツ、または事実確認が不十分な内容をアップロードすること。","s7.l3":"ご自身の身元、資格、または居住地を偽ること。","s7.l4":"違法行為または無許可のサービスを宣伝するためにプラットフォームを利用すること。","s7.l5":"Journey Junction の API またはダッシュボードに対し、リバースエンジニアリング、スクレイピング、または不正な利用を行うこと。","s8.title":"停止および解除","s8.p1":"当社は、期限の度重なる超過、品質の低い成果物、サポート窓口の不正利用、禁止行為、または規制上の理由により、事前の通知の有無を問わず、プランナーのアカウントを停止または解除することがあります。","s8.p2":"解除された場合、プランナーは未受注のセットへのアクセス権、および未解決の問題の裁定が完了するまで支払われていない報酬を失います。すでに承認され支払われた報酬は、引き続きプランナーに帰属します。","s9.title":"責任および免責事項","s9.p1":"Journey Junction は<strong>「現状有姿」</strong>で提供されます。当社は、利用可能なセットの量、プランナーが得られる収益、またはサービスが中断されないことについて、いかなる保証も行いません。法律で認められる最大限の範囲において、いかなる争議に関しても、プランナーに対する当社の総責任額は、<strong>請求の直前3か月間</strong>にプランナーへ支払われた報酬の額を上限とします。","s10.title":"本規約の変更","s10.p1":"当社は、随時本規約を更新することがあります。重要な変更については、発効の少なくとも14日前までにダッシュボードを通じて告知します。当該発効日以降にプラットフォームの利用を継続することは、変更への同意とみなされます。","s11.title":"準拠法","s11.p1":"本規約は、日本法に準拠するものとします。Journey Junction Ltd は英国で設立された法人ですが、本サービスは日本市場向けに提供されています。紛争が生じた場合、当事者間で誠実に協議し、解決を図るものとします。協議によって解決しない場合は、東京地方裁判所を第一審の専属的合意管轄裁判所とします。","contact.title":"お問い合わせ","contact.body":"本規約についてご質問がございますか？ <a href=\"support.html\">アプリ内のサポートチャット</a>からご連絡いただくか、<strong>hello@thejourneyjunction.co.uk</strong> 宛てにメールでお問い合わせください。","company.title":"会社情報","company.body":"<strong>Journey Junction Ltd</strong><br>会社番号：15791277 · 設立日：2024年6月20日<br>登記上の所在地：Flat 2, 64 Heathmere Drive, Birmingham, West Midlands, B37 5EU, United Kingdom<br>取締役：Midhun Peter"}}'::jsonb, 'seed')
on conflict (slug) do nothing;

